mapper.select:
SELECT * FROM lottery_record
WHERE student_id = #{studentId} AND is_redeemed = #{isRedeemed}
ORDER BY lottery_time DESC

SELECT lr.id, lr.student_id, s.real_name AS student_name, lr.item_id, lr.item_name, lr.lottery_time, lr.is_redeemed, lr.redeemed_time, op.real_name AS redeemed_by_name FROM lottery_record lr LEFT JOIN user s ON lr.student_id = s.id LEFT JOIN user op ON lr.redeemed_by = op.id WHERE s.parent_id = #{parentId}
AND lr.student_id = #{studentId}
AND lr.is_redeemed = #{isRedeemed}
ORDER BY lr.lottery_time DESC

SELECT DISTINCT lr.* FROM lottery_record lr
INNER JOIN user s ON lr.student_id = s.id AND s.parent_id = #{parentId}
WHERE lr.is_redeemed = 0
AND lr.student_id = #{studentId}

    AND (
        lr.item_id IN #{id}
        OR lr.item_name IN (
            SELECT name FROM lottery_item WHERE id IN
            #{id}
        )
    )

mapper.update:
UPDATE lottery_record
is_redeemed = #{isRedeemed}, redeemed_time = #{redeemedTime}, redeemed_by = #{redeemedBy},
WHERE id = #{id}
